let webhookData = $input.first().json.body || $input.first().json;

if (typeof webhookData === 'string') {
  webhookData = JSON.parse(webhookData);
}

const docUrl = webhookData.doc_url;
const title = webhookData.title || webhookData.doc_title || 'Untitled';

if (!docUrl) {
  throw new Error('No doc_url in webhook payload. Received: ' + JSON.stringify(webhookData));
}

const match = docUrl.match(/\/documents\/(\d+)/);
if (!match) {
  throw new Error('Could not parse document ID from doc_url: ' + docUrl);
}

return [{ json: { document_id: match[1], title: title, doc_url: docUrl } }];

const docNode = $('Fetch Document Details').first().json;
const tagsResponse = $input.first().json;
const allTags = tagsResponse.results || tagsResponse || [];

const documentId = docNode.id;
const title = docNode.title;
const tagIds = docNode.tags || [];

const tagNames = [];
for (const tagId of tagIds) {
  const tag = allTags.find(t => t.id === tagId);
  if (tag) tagNames.push(tag.name);
}

const systemTags = ['inbox', 'processed', 'pending', 'review', 'archive', 'intake'];
let familyId = 'unknown';
for (const tagName of tagNames) {
  if (!systemTags.includes(tagName.toLowerCase())) {
    familyId = tagName.toLowerCase();
    break;
  }
}

return [{ json: {
  document_id: String(documentId),
  title: title,
  family_id: familyId,
  tag_names: tagNames,
  download_url: 'http://paperless:8000/api/documents/' + documentId + '/download/'
}}];

// Extract task_id from Docling response
const response = $input.first().json;
console.log('Docling start response:', JSON.stringify(response));

const taskId = response.task_id || response.id || response.taskId;

if (!taskId) {
  // Maybe it returned the result directly (sync mode)?
  if (response.document || response.documents || response.md_content) {
    // Direct result - skip polling
    return [{ json: { direct_result: true, result: response } }];
  }
  throw new Error('No task_id in Docling response: ' + JSON.stringify(response));
}

return [{ json: { task_id: taskId, poll_count: 0, direct_result: false } }];

const statusResponse = $input.first().json;
const prevData = $('Wait 5s').first().json;
const taskId = prevData.task_id;
const pollCount = (prevData.poll_count || 0) + 1;

console.log('Poll #' + pollCount + ' - Response:', JSON.stringify(statusResponse));

// Handle array response
const status_obj = Array.isArray(statusResponse) ? statusResponse[0] : statusResponse;
const status = (status_obj.task_status || status_obj.status || status_obj.state || 'unknown').toLowerCase();

console.log('Status:', status);

// Check if conversion is complete
if (status === 'success' || status === 'completed' || status === 'done' || status === 'finished') {
  return [{ json: { task_id: taskId, is_complete: true, poll_count: pollCount } }];
}

// Check for failure - get error details
if (status === 'failure' || status === 'failed' || status === 'error') {
  const errorMsg = status_obj.task_meta || status_obj.error || status_obj.message || 'Unknown error';
  throw new Error('Docling conversion FAILED: ' + JSON.stringify(errorMsg) + '. Full response: ' + JSON.stringify(status_obj));
}

// Still processing - check if we've exceeded max polls (60 = 5 minutes)
if (pollCount >= 60) {
  throw new Error('Docling conversion timed out after 5 minutes. Last status: ' + JSON.stringify(statusResponse));
}

// Not complete yet, continue polling
return [{ json: { task_id: taskId, is_complete: false, poll_count: pollCount } }];

// Get result from either direct response or fetched result
let doclingResponse;
const directCheck = $('Direct Result?');
if (directCheck && directCheck.first) {
  const directData = directCheck.first().json;
  if (directData.direct_result && directData.result) {
    doclingResponse = directData.result;
  }
}
if (!doclingResponse) {
  doclingResponse = $input.first().json;
}

const extractNode = $('Extract Document Info').first().json;
const documentId = extractNode.document_id;
const familyId = extractNode.family_id;
const title = extractNode.title;

let markdown = '';
let pageData = []; // Array of {page: N, text: '...'} for page tracking

console.log('Docling result keys:', Object.keys(doclingResponse));

// Try to extract page-aware content from Docling's structured output
if (doclingResponse.document) {
  const doc = doclingResponse.document;
  // Check for pages array with page info
  if (doc.pages && Array.isArray(doc.pages)) {
    doc.pages.forEach((page, idx) => {
      const pageText = page.text || page.content || page.md_content || '';
      if (pageText) pageData.push({ page: idx + 1, text: pageText });
    });
  }
  // Check for texts array with page metadata
  if (doc.texts && Array.isArray(doc.texts)) {
    doc.texts.forEach(t => {
      const pageNum = t.page || t.page_number || t.page_no || 1;
      const text = t.text || t.content || '';
      if (text) pageData.push({ page: pageNum, text: text });
    });
  }
  markdown = doc.md_content || doc.text_content || doc.markdown || '';
} else if (doclingResponse.documents && doclingResponse.documents.length > 0) {
  const doc = doclingResponse.documents[0];
  if (doc.pages) {
    doc.pages.forEach((page, idx) => {
      const pageText = page.text || page.content || '';
      if (pageText) pageData.push({ page: idx + 1, text: pageText });
    });
  }
  markdown = doc.md_content || doc.text_content || doc.markdown || '';
} else if (doclingResponse.md_content) {
  markdown = doclingResponse.md_content;
} else if (doclingResponse.markdown) {
  markdown = doclingResponse.markdown;
} else if (doclingResponse.text) {
  markdown = doclingResponse.text;
} else if (doclingResponse.result) {
  const res = doclingResponse.result;
  markdown = res.md_content || res.markdown || res.text || '';
}

// If no page data extracted, try to parse page markers from markdown
if (pageData.length === 0 && markdown) {
  // Look for page markers: <!-- Page N -->, [Page N], ---Page N---, \f (form feed)
  const pageMarkerRegex = /(?:<!-+\s*Page\s*(\d+)\s*-+>|\[Page\s*(\d+)\]|---+\s*Page\s*(\d+)\s*---+|\x0c)/gi;
  const parts = markdown.split(pageMarkerRegex);

  let currentPage = 1;
  let currentText = '';

  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];
    if (!part) continue;

    // Check if this part is a page number
    const pageNum = parseInt(part, 10);
    if (!isNaN(pageNum) && pageNum > 0 && pageNum < 1000) {
      // Save current page text
      if (currentText.trim()) {
        pageData.push({ page: currentPage, text: currentText.trim() });
      }
      currentPage = pageNum;
      currentText = '';
    } else {
      currentText += part;
    }
  }
  // Don't forget the last page
  if (currentText.trim()) {
    pageData.push({ page: currentPage, text: currentText.trim() });
  }
}

// If still no page data, estimate pages (~3000 chars per page)
if (pageData.length === 0 && markdown) {
  const CHARS_PER_PAGE = 3000;
  for (let i = 0; i < markdown.length; i += CHARS_PER_PAGE) {
    const pageNum = Math.floor(i / CHARS_PER_PAGE) + 1;
    const pageText = markdown.substring(i, i + CHARS_PER_PAGE);
    pageData.push({ page: pageNum, text: pageText });
  }
}

console.log('Extracted', pageData.length, 'pages from document');

// Create chunks with proper page numbers
const chunks = [];
let chunkIndex = 0;

for (const pageInfo of pageData) {
  const pageText = pageInfo.text.trim();
  if (pageText.length < 30) continue;

  // Split by headers within the page
  let sections = pageText.split(/(?=^#{1,2} )/gm).filter(s => s.trim().length > 20);
  if (sections.length === 0) sections = [pageText];

  for (const section of sections) {
    const parentText = section.trim();
    if (parentText.length < 30) continue;

    const words = parentText.split(/\s+/);
    for (let i = 0; i < words.length; i += 80) {
      const childText = words.slice(i, i + 100).join(' ');
      if (childText.length < 30) continue;
      chunks.push({
        chunk_index: chunkIndex++,
        document_id: String(documentId),
        document_title: title,
        family_id: familyId,
        text: childText,
        context_text: parentText.substring(0, 2000),
        page_num: pageInfo.page
      });
    }
  }
}

// Fallback if no chunks created
if (chunks.length === 0) {
  const fallbackText = pageData.length > 0 ? pageData[0].text : markdown;
  chunks.push({
    chunk_index: 0,
    document_id: String(documentId),
    document_title: title,
    family_id: familyId,
    text: (fallbackText || '').substring(0, 500),
    context_text: (fallbackText || '').substring(0, 2000),
    page_num: 1
  });
}

console.log('Created', chunks.length, 'chunks with family_id:', familyId, 'and page tracking');
return chunks.map(chunk => ({ json: chunk }));

// Simple hash function for BM25 sparse vector generation
function hashCode(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32-bit integer
  }
  return Math.abs(hash);
}

// Get chunk data from previous node
const chunkData = $('Chunk Markdown').item.json;
const embedding = $json.embedding;

if (!embedding || !Array.isArray(embedding)) {
  throw new Error('Failed to get embedding from Ollama. Response: ' + JSON.stringify($json));
}

// Generate BM25-compatible sparse vector from the chunk text
const text = chunkData.text.toLowerCase();
const words = text.split(/\W+/).filter(w => w.length > 2);
const wordCounts = {};
words.forEach(w => { wordCounts[w] = (wordCounts[w] || 0) + 1; });

// Convert to sparse format: {indices: [], values: []}
const indices = [];
const values = [];
Object.entries(wordCounts).forEach(([word, count]) => {
  indices.push(hashCode(word) % 30000);  // Hash to fixed vocab size
  values.push(count);
});

// Create integer point ID: document_id * 10000 + chunk_index
const pointId = parseInt(chunkData.document_id) * 10000 + chunkData.chunk_index;

return { json: {
  point_id: pointId,
  dense_vector: embedding,
  sparse_vector: { indices: indices, values: values },
  payload: chunkData
}};

// Loop back to Wait node with updated poll count
const taskId = $json.task_id;
const pollCount = $json.poll_count;
return [{ json: { task_id: taskId, poll_count: pollCount } }];

// Direct result path - extract from response
const data = $input.first().json;
return [{ json: data.result }];
